const row = $('/learn: pg INSERT material').item.json;
const materialId = row.id;
const chatId = row.chat_id;
const title = row.title || 'Untitled';
const summary = row.summary_json;
const lang = $('lang: pg load /learn').item.json.lang || 'en';
const t = T[lang] || T.en;

function esc(s) { return String(s == null ? '' : s).replace(/([_*`\[])/g, '\\$1'); }

const diffEmoji = { beginner: '🟢', intermediate: '🟡', advanced: '🔴' }[summary.difficulty] || '⚪';

const keyPointsBlock = summary.key_points.map((p, i) => `${i + 1}. ${esc(p)}`).join('\n');
const conceptsBlock = summary.main_concepts.map((c) => `\`${esc(c)}\``).join(' · ');
const interviewBlock = summary.interview_angle ? `\n💡 *${t.interviewAngle}:* _${esc(summary.interview_angle)}_` : '';

const text = `📚 *${esc(title)}*\n${diffEmoji} _${esc(summary.difficulty)}_\n\n*${t.keyPoints}:*\n${keyPointsBlock}\n\n*${t.concepts}:* ${conceptsBlock}${interviewBlock}\n\n${t.summaryFooter}`;

const reply_markup = {
  inline_keyboard: [[{ text: t.takeQuizNow, callback_data: `pick:${materialId}` }]]
};

const body_json = JSON.stringify({ chat_id: chatId, text, parse_mode: 'Markdown', reply_markup });
return [{ json: { chat_id: chatId, text, reply_markup, body_json } }];

const chatId = $('Telegram Trigger1').item.json.message.chat.id;
const rows = $input.all().map(i => i.json);

let text, reply_markup;
if (!rows || rows.length === 0 || !rows[0].id) {
  text = '\u{1F4ED} *No saved materials yet.*\n\nSend `/learn [URL]` first.';
  reply_markup = undefined;
} else {
  const diffEmoji = { beginner: '\u{1F7E2}', intermediate: '\u{1F7E1}', advanced: '\u{1F534}' };
  const inline_keyboard = rows.map((r) => [{
    text: `${diffEmoji[r.difficulty] || '\u26AA\uFE0F'} ${(r.title || 'Untitled').slice(0, 60)}`,
    callback_data: `pick:${r.id}`
  }]);
  text = `\u{1F4DA} *Pick a topic to quiz on:*\n\nYou have ${rows.length} saved material${rows.length === 1 ? '' : 's'}.`;
  reply_markup = { inline_keyboard };
}

const payload = { chat_id: chatId, text, parse_mode: 'Markdown' };
if (reply_markup) payload.reply_markup = reply_markup;
const body_json = JSON.stringify(payload);
return [{ json: { chat_id: chatId, body_json } }];

const mat = $('pick: pg load material').item.json;
const response = $input.first().json;
const rawText = response?.content?.[0]?.text || '';

let parsed;
try {
  const cleaned = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error('Examiner returned unparseable JSON: ' + rawText.slice(0, 300));
}

if (!Array.isArray(parsed.questions) || parsed.questions.length !== 5) {
  throw new Error('Examiner did not return 5 questions, got: ' + (parsed.questions || []).length);
}

// Validate each question + RANDOMIZE option order so correctAnswer isn't always A
const letters = ['A','B','C','D'];
for (let i = 0; i < 5; i++) {
  const q = parsed.questions[i];
  if (!q.id) q.id = `Q${i + 1}`;
  if (!q.options || !q.options.A || !q.options.B || !q.options.C || !q.options.D) {
    throw new Error(`Q${i + 1} missing options A-D`);
  }
  q.correctAnswer = String(q.correctAnswer || '').toUpperCase();
  if (!letters.includes(q.correctAnswer)) {
    throw new Error(`Q${i + 1} has invalid correctAnswer: ${q.correctAnswer}`);
  }
  q.explanation = q.explanation || '';

  // Shuffle option order to spread correctAnswer across A/B/C/D
  const correctText = q.options[q.correctAnswer];
  const wrongTexts = letters.filter(l => l !== q.correctAnswer).map(l => q.options[l]);
  // Fisher-Yates shuffle wrongTexts
  for (let j = wrongTexts.length - 1; j > 0; j--) {
    const k = Math.floor(Math.random() * (j + 1));
    [wrongTexts[j], wrongTexts[k]] = [wrongTexts[k], wrongTexts[j]];
  }
  // Pick random target slot for the correct answer
  const targetLetter = letters[Math.floor(Math.random() * 4)];
  const newOptions = {};
  let wi = 0;
  for (const L of letters) {
    if (L === targetLetter) newOptions[L] = correctText;
    else newOptions[L] = wrongTexts[wi++];
  }
  q.options = newOptions;
  q.correctAnswer = targetLetter;
}

return [{ json: { material_id: mat.material_id, chat_id: mat.chat_id, questions: parsed.questions } }];

const row = $input.first().json;
const quizId = row.id;
const chatId = row.chat_id;
const questions = (row.questions && row.questions.questions) || row.questions;
const q = questions[0];

function esc(s) { return String(s == null ? '' : s).replace(/([_*`\[])/g, '\\$1'); }

const text = `\u{1F3AF} *Question 1 of 5*\n\n${esc(q.question)}\n\n*A)* ${esc(q.options.A)}\n*B)* ${esc(q.options.B)}\n*C)* ${esc(q.options.C)}\n*D)* ${esc(q.options.D)}`;

const reply_markup = {
  inline_keyboard: [
    [
      { text: 'A', callback_data: `ans:${quizId}:${q.id}:A` },
      { text: 'B', callback_data: `ans:${quizId}:${q.id}:B` },
    ],
    [
      { text: 'C', callback_data: `ans:${quizId}:${q.id}:C` },
      { text: 'D', callback_data: `ans:${quizId}:${q.id}:D` },
    ],
  ]
};

const body_json = JSON.stringify({ chat_id: chatId, text, parse_mode: 'Markdown', reply_markup });
return [{ json: { chat_id: chatId, body_json } }];

// Parse answer callback: ans:<quiz_id>:Qn:X
const cb = $input.first().json.callback_query;
const data = cb.data || '';
const parts = data.split(':');
if (parts.length !== 4 || parts[0] !== 'ans') {
  throw new Error('Malformed answer callback: ' + data);
}
const quizId = parseInt(parts[1], 10);
const questionId = parts[2];
const userAnswer = parts[3].toUpperCase();
const chatId = cb.message.chat.id;
const messageId = cb.message.message_id;

return [{ json: { quiz_id: quizId, question_id: questionId, user_answer: userAnswer, chat_id: chatId, message_id: messageId } }];

// Validate answer, build next-state payload (next Q or final results)
const quizRow = $input.first().json;
const { quiz_id, question_id, user_answer, chat_id } = $('ans: parse callback').item.json;

const rawQuestions = quizRow.questions;
const questions = (rawQuestions && rawQuestions.questions) || rawQuestions;
const qIdx = questions.findIndex(q => q.id === question_id);
if (qIdx < 0) throw new Error('Question ' + question_id + ' not in quiz ' + quiz_id);

const q = questions[qIdx];
const correctAnswer = String(q.correctAnswer).toUpperCase();
const correct = user_answer === correctAnswer;
const isLast = qIdx === questions.length - 1;
const nextIdx = qIdx + 1;

// Build payload for downstream INSERT into quiz_answers
const payload = {
  quiz_id,
  question_id,
  user_answer,
  correct_answer: correctAnswer,
  correct,
  is_last: isLast,
  chat_id,
  current_q_idx: qIdx,
  next_q_idx: nextIdx,
  questions, // pass forward for downstream formatting
  user_option_text: q.options[user_answer] || '',
  correct_option_text: q.options[correctAnswer] || '',
  explanation: q.explanation || '',
};

return [{ json: payload }];

parameters.query:
INSERT INTO app.quiz_answers (quiz_id, question_id, user_answer, correct)
VALUES (
  {{ $json.quiz_id }},
  '{{ $json.question_id.replace(/'/g, "''") }}',
  '{{ $json.user_answer.replace(/'/g, "''") }}',
  {{ $json.correct }}
)
ON CONFLICT (quiz_id, question_id) DO NOTHING
RETURNING id;

SELECT qa.question_id, qa.user_answer, qa.correct, q.questions
FROM app.quiz_answers qa
JOIN app.quizzes q ON q.id = qa.quiz_id
WHERE qa.quiz_id = {{ $('poll_ans: validate').isExecuted ? $('poll_ans: validate').item.json.quiz_id : $('ans: validate').item.json.quiz_id }}
ORDER BY qa.question_id;

