const chatId = $('Telegram Trigger1').item.json.message.chat.id;
const row = $('/stats: pg load').item.json;
const lang = (row && row.lang) || $('lang: pg load /stats').item.json.lang || 'en';
const t = T[lang] || T.en;

const dashUrl = `https://seniorprepcoach.ngrok.dev/webhook/dashboard?chat_id=${chatId}&lang=${lang}`;
const reply_markup = {
  inline_keyboard: [[
    { text: t.openDashboard, web_app: { url: dashUrl } }
  ]]
};

if (!row || row.materials_count === undefined || row.materials_count === null || row.materials_count === 0) {
  const text = `📊 *${t.noHistory}*\n\n${t.noHistoryHint}`;
  const body_json = JSON.stringify({ chat_id: chatId, text, parse_mode: 'Markdown' });
  return [{ json: { chat_id: chatId, text, body_json } }];
}

function bar(n, total = 10) {
  const filled = Math.min(total, Math.max(0, Math.round((n / 100) * total)));
  return '█'.repeat(filled) + '░'.repeat(total - filled);
}

const score = Number(row.avg_score_pct) || 0;
const lastQuiz = row.last_quiz_at ? new Date(row.last_quiz_at).toISOString().split('T')[0] : t.never;

const lines = [
  `📊 *${t.yourDashboard}*`,
  '',
  `📚 *${t.materialsSaved}:* ${row.materials_count}`,
  `   🟢 beginner: ${row.beginner_materials || 0}`,
  `   🟡 intermediate: ${row.intermediate_materials || 0}`,
  `   🔴 advanced: ${row.advanced_materials || 0}`,
  '',
  `🎯 *${t.quizzesTaken}:* ${row.quizzes_taken || 0}`,
  `📈 *${t.avgScore}:* ${score}%`,
  `      \`${bar(score)}\``,
  `🕒 *${t.lastQuiz}:* ${lastQuiz}`,
  '',
  `_${t.retentionTip}_`,
];

const text = lines.join('\n');
const body_json = JSON.stringify({ chat_id: chatId, text, parse_mode: 'Markdown', reply_markup });
return [{ json: { chat_id: chatId, text, body_json } }];

const lang = $('lang: pg load pick').item.json.lang || 'en';
const langDirective = lang === 'ru'
  ? '

All output strings (question, options A/B/C/D, explanation) must be in Russian. Answer letters stay A/B/C/D.'
  : '';
// Build the Anthropic Examiner request body as a JSON string here.
const mat = $('pick: pg load material').item.json;

let systemPrompt = "You are the Examiner in an AI-powered learning assistant for senior backend engineers preparing for staff-tier interviews. Given a material title, summary, and full content, generate EXACTLY 5 multiple-choice questions that probe whether the reader internalized the material at senior interview level.

STYLE non-negotiable:
1. NO trivia. No year/acronym recall.
2. PROBE understanding: apply concept to scenario, compare approaches, identify failure mode, spot what breaks if assumption changes.
3. INTERVIEW FRAMING: phrase as interviewer would speak it.
4. PLAUSIBLE DISTRACTORS: wrong options represent real misconceptions.
5. ONE CORRECT ANSWER each (single best answer).
6. EXPLANATIONS MUST TEACH why right is right AND why distractors are wrong.
7. NO HARDCODING.

Output JSON with EXACTLY this schema:
{
  "questions": [
    { "id": "Q1", "question": "<=280 chars", "options": { "A": "<=120", "B": "<=120", "C": "<=120", "D": "<=120" }, "correctAnswer": "A"|"B"|"C"|"D", "explanation": "<2-4 sentences>" }, ...Q2-Q5
  ]
}

Exactly 5 questions, IDs Q1-Q5, 4 options A-D each, correctAnswer single A-D letter. Distribute correct answers across A/B/C/D.

Output ONLY the JSON. No fences, no commentary.";
systemPrompt += langDirective;


const summary = mat.summary_json || {};
const keyPoints = Array.isArray(summary.key_points) ? summary.key_points.join('
') : '';
const concepts = Array.isArray(summary.main_concepts) ? summary.main_concepts.join(', ') : '';
const userContent = 'TITLE: ' + (mat.title || '') + '
DIFFICULTY: ' + (mat.difficulty || '') + '

KEY POINTS:
' + keyPoints + '

CONCEPTS: ' + concepts + '

FULL CONTENT:
' + (mat.content || '');

const examiner_body = JSON.stringify({
  model: 'claude-sonnet-4-5',
  max_tokens: 3500,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
});

return [{ json: { ...mat, examiner_body } }];

// Build sendPoll quiz-mode body.
// Inputs may be:
//   (a) pick: pg INSERT quiz output — has fields: id (quiz_id), material_id, chat_id, questions (JSONB)
//   (b) poll_ans: validate output — has fields: quiz_id, chat_id, next_q_idx, questions

const ctx = $input.first().json;

const quizId = ctx.quiz_id !== undefined ? ctx.quiz_id : ctx.id;
const chatId = ctx.chat_id;
const questions = (ctx.questions && ctx.questions.questions) || ctx.questions;
const qIdx = ctx.next_q_idx !== undefined ? ctx.next_q_idx : 0;
const q = questions[qIdx];

const letters = ['A', 'B', 'C', 'D'];
// Each option: prefix with letter for clarity, then truncate to Telegram 100-char limit
const options = letters.map(L => {
  const raw = `${L}) ${q.options[L] || ''}`;
  return raw.length > 100 ? raw.slice(0, 97) + '...' : raw;
});
const correctOptionId = letters.indexOf(q.correctAnswer);
if (correctOptionId === -1) throw new Error('Invalid correctAnswer: ' + q.correctAnswer);

// Telegram explanation: 200 chars max
let explanation = q.explanation || '';
if (explanation.length > 200) explanation = explanation.slice(0, 197) + '...';

// Question text: Telegram poll question max 300 chars
let questionText = `Q${qIdx + 1} of ${questions.length}: ${q.question}`;
if (questionText.length > 300) questionText = questionText.slice(0, 297) + '...';

const body_json = JSON.stringify({
  chat_id: chatId,
  type: 'quiz',
  question: questionText,
  options: options,
  correct_option_id: correctOptionId,
  explanation: explanation,
  is_anonymous: false
});

return [{ json: {
  chat_id: chatId,
  quiz_id: quizId,
  question_id: q.id,
  question_idx: qIdx,
  correct_option_id: correctOptionId,
  body_json
} }];

const resp = $input.first().json;
const pollId = resp?.result?.poll?.id;
if (!pollId) throw new Error('No poll.id in sendPoll response');

// Try pick path first, fallback to poll_ans path
let builder;
if ($('pick: build poll body').isExecuted) {
  builder = $('pick: build poll body').item.json;
} else if ($('poll_ans: build next poll body').isExecuted) {
  builder = $('poll_ans: build next poll body').item.json;
} else {
  throw new Error('No build body node executed in this run');
}

return [{ json: {
  poll_id: pollId,
  quiz_id: builder.quiz_id,
  chat_id: builder.chat_id,
  question_id: builder.question_id,
  question_idx: builder.question_idx,
  correct_option_id: builder.correct_option_id
} }];

const pa = $input.first().json.poll_answer;
if (!pa) throw new Error('No poll_answer payload');
return [{ json: {
  poll_id: pa.poll_id,
  chat_id: pa.user?.id,
  selected_option_id: (pa.option_ids || [])[0]
} }];

const row = $input.first().json;
const pa = $('poll_ans: parse').item.json;

const correct = pa.selected_option_id === row.correct_option_id;
const letters = ['A','B','C','D'];
const userAnswer = letters[pa.selected_option_id] || '?';
const correctAnswer = letters[row.correct_option_id] || '?';

const questions = (row.questions && row.questions.questions) || row.questions;
const isLast = row.question_idx === questions.length - 1;
const nextIdx = row.question_idx + 1;

return [{ json: {
  quiz_id: row.quiz_id,
  chat_id: row.chat_id,
  question_id: row.question_id,
  question_idx: row.question_idx,
  next_q_idx: nextIdx,
  user_answer: userAnswer,
  correct_answer: correctAnswer,
  correct,
  is_last: isLast,
  questions
} }];

parameters.query:
INSERT INTO app.quiz_answers (quiz_id, question_id, user_answer, correct)
VALUES (
  {{ $json.quiz_id }},
  '{{ $json.question_id.replace(/'/g, "''") }}',
  '{{ $json.user_answer.replace(/'/g, "''") }}',
  {{ $json.correct }}
)
ON CONFLICT (quiz_id, question_id) DO NOTHING
RETURNING id;

parameters.jsCode:
const v = $('poll_ans: validate').item.json;
const questions = v.questions;
const qIdx = v.next_q_idx;
const q = questions[qIdx];

const letters = ['A', 'B', 'C', 'D'];
const options = letters.map(L => {
  const raw = L + ') ' + (q.options[L] || '');
  return raw.length > 100 ? raw.slice(0, 97) + '...' : raw;
});
const correctOptionId = letters.indexOf(q.correctAnswer);

let explanation = q.explanation || '';
if (explanation.length > 200) explanation = explanation.slice(0, 197) + '...';

let questionText = 'Q' + (qIdx + 1) + ' of ' + questions.length + ': ' + q.question;
if (questionText.length > 300) questionText = questionText.slice(0, 297) + '...';

const body_json = JSON.stringify({
  chat_id: v.chat_id,
  type: 'quiz',
  question: questionText,
  options,
  correct_option_id: correctOptionId,
  explanation,
  is_anonymous: false
});

return [{ json: {
  chat_id: v.chat_id,
  quiz_id: v.quiz_id,
  question_id: q.id,
  question_idx: qIdx,
  correct_option_id: correctOptionId,
  body_json
} }];

// Render premium Mini App HTML
const row = $input.first().json || {};
const materials = row.materials || [];
const quizzes = row.quizzes || [];
const activity = row.activity || [];
const total = row.materials_count || 0;
const taken = row.quizzes_taken || 0;
const avg = Math.round(row.avg_score_pct || 0);
const beg = row.beginner_materials || 0;
const inter = row.intermediate_materials || 0;
const adv = row.advanced_materials || 0;
const perfectQ = row.perfect_quizzes || 0;
const bestScore = row.best_score || 0;
const lastAt = row.last_quiz_at ? new Date(row.last_quiz_at).toISOString().split('T')[0] : null;

function esc(s) {
  return String(s == null ? '' : s)
    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;').replace(/'/g,'&#039;');
}

// Achievements
const achievements = [
  { icon: '🌱', title: 'First spark',     sub: 'Saved your first material', unlocked: total >= 1 },
  { icon: '📚', title: 'Library starter', sub: '5+ materials saved',         unlocked: total >= 5 },
  { icon: '🎯', title: 'Initiate',        sub: 'Took your first quiz',       unlocked: taken >= 1 },
  { icon: '🔥', title: 'On a roll',       sub: 'Took 5+ quizzes',            unlocked: taken >= 5 },
  { icon: '💎', title: 'Perfectionist',   sub: 'Hit 100% on a quiz',         unlocked: perfectQ >= 1 },
  { icon: '🏆', title: 'Top form',        sub: 'Personal best ≥ 80%',        unlocked: bestScore >= 80 },
  { icon: '🦉', title: 'Triple stack',    sub: 'All 3 difficulty levels',    unlocked: beg > 0 && inter > 0 && adv > 0 },
];

const badges = achievements.map(a => `
  <div class="badge ${a.unlocked ? 'on' : 'off'}">
    <div class="badge-icon">${a.icon}</div>
    <div class="badge-title">${esc(a.title)}</div>
    <div class="badge-sub">${esc(a.sub)}</div>
  </div>`).join('');

// Library rows
const matRows = materials.map(m => {
  const score = m.best_score;
  const scoreBlock = score != null
    ? `<div class="score-mini"><div class="sm-track"><div class="sm-fill" style="width:${score}%"></div></div><span class="sm-val">${score}%</span></div>`
    : `<div class="lib-meta dim">never quizzed</div>`;
  return `
    <div class="lib-row">
      <div class="lib-icon ${esc(m.difficulty)}">${m.difficulty === 'advanced' ? '🔴' : m.difficulty === 'intermediate' ? '🟡' : '🟢'}</div>
      <div class="lib-body">
        <div class="lib-title">${esc(m.title)}</div>
        ${scoreBlock}
      </div>
    </div>`;
}).join('');

// Heatmap: last 28 days
const activityMap = {};
activity.forEach(a => { activityMap[a.day] = a; });
const heatCells = [];
const today = new Date();
today.setUTCHours(0,0,0,0);
for (let i = 27; i >= 0; i--) {
  const d = new Date(today);
  d.setUTCDate(d.getUTCDate() - i);
  const key = d.toISOString().split('T')[0];
  const day = activityMap[key];
  let level = 0;
  if (day) {
    if (day.cnt >= 3 || day.avg_pct >= 80) level = 4;
    else if (day.cnt >= 2 || day.avg_pct >= 60) level = 3;
    else if (day.avg_pct >= 40) level = 2;
    else level = 1;
  }
  const title = day ? `${key}: ${day.cnt} quiz${day.cnt > 1 ? 'zes' : ''}, ${day.avg_pct}% avg` : key;
  heatCells.push(`<div class="cell l${level}" title="${title}"></div>`);
}

// Quiz history items
const quizRows = quizzes.slice().reverse().slice(0, 8).map(q => {
  const cls = q.score_pct >= 80 ? 'good' : q.score_pct >= 60 ? 'mid' : q.score_pct >= 40 ? 'low' : 'bad';
  return `
    <div class="quiz-row">
      <div class="quiz-title">${esc(q.title)}</div>
      <div class="quiz-meta">${esc(q.finished_at)}</div>
      <div class="score-bar">
        <div class="sb-track"><div class="sb-fill ${cls}" data-fill="${q.score_pct}" style="width:0%"></div></div>
        <span class="sb-val">${q.score_pct}%</span>
      </div>
    </div>`;
}).join('');

const lastBlock = lastAt ? `Last quiz · ${lastAt}` : 'Take a quiz to see your stats';

const chartData = {
  diff: [beg, inter, adv],
  scores: quizzes.map(q => q.score_pct),
  labels: quizzes.map((q, i) => `#${i+1}`),
  titles: quizzes.map(q => q.title),
};

const html = `<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover,user-scalable=no">
<title>Senior Backend Coach — Dashboard</title>
<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js"></script>
<script src="https://telegram.org/js/telegram-web-app.js"></script>
<style>
  :root {
    --tg-bg: var(--tg-theme-bg-color, #0f1115);
    --tg-fg: var(--tg-theme-text-color, #ECEFF4);
    --tg-hint: var(--tg-theme-hint-color, #8a93a0);
    --tg-button: var(--tg-theme-button-color, #5b8aff);
    --tg-button-text: var(--tg-theme-button-text-color, #ffffff);
    --tg-secondary-bg: var(--tg-theme-secondary-bg-color, #1c1f26);
    --accent: #5b8aff;
    --accent-2: #b07cff;
    --accent-3: #ff7eb6;
    --success: #34c759;
    --warn: #ffcc00;
    --danger: #ff453a;
    --card: rgba(255,255,255,0.04);
    --card-h: rgba(255,255,255,0.07);
    --border: rgba(255,255,255,0.08);
    --border-s: rgba(255,255,255,0.14);
    --radius: 16px;
    --radius-sm: 10px;
  }
  *, *::before, *::after { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }
  html, body { margin: 0; padding: 0; }
  body {
    background: var(--tg-bg);
    color: var(--tg-fg);
    font: 14.5px/1.5 -apple-system, BlinkMacSystemFont, "Inter", "SF Pro Text", "Segoe UI", Roboto, sans-serif;
    padding-bottom: 80px;
    overscroll-behavior: contain;
    letter-spacing: -0.011em;
    min-height: 100vh;
  }

  /* HERO */
  .hero {
    position: relative;
    padding: 28px 18px 78px;
    overflow: hidden;
    background:
      radial-gradient(ellipse 80% 60% at 50% -10%, rgba(91,138,255,0.30) 0%, transparent 60%),
      radial-gradient(ellipse 60% 50% at 110% 20%, rgba(176,124,255,0.20) 0%, transparent 60%),
      radial-gradient(ellipse 50% 40% at -10% 50%, rgba(255,126,182,0.10) 0%, transparent 60%);
  }
  .hero::before, .hero::after {
    content: '';
    position: absolute;
    width: 320px; height: 320px;
    border-radius: 50%;
    filter: blur(50px);
    opacity: 0.6;
    pointer-events: none;
  }
  .hero::before {
    top: -160px; right: -80px;
    background: radial-gradient(circle, rgba(91,138,255,0.45) 0%, transparent 70%);
    animation: floatA 14s ease-in-out infinite;
  }
  .hero::after {
    bottom: -100px; left: -100px;
    background: radial-gradient(circle, rgba(176,124,255,0.35) 0%, transparent 70%);
    animation: floatB 18s ease-in-out infinite;
  }
  @keyframes floatA { 0%,100% { transform: translate(0,0); } 50% { transform: translate(-40px,30px); } }
  @keyframes floatB { 0%,100% { transform: translate(0,0); } 50% { transform: translate(50px,-25px); } }

  .hero-head { display: flex; align-items: center; gap: 10px; margin-bottom: 6px; }
  .hero-emoji {
    font-size: 32px;
    filter: drop-shadow(0 6px 18px rgba(91,138,255,0.5));
    animation: pulse 4s ease-in-out infinite;
  }
  @keyframes pulse { 0%,100% { transform: scale(1); } 50% { transform: scale(1.08); } }

  h1 { margin: 0; font-size: 24px; font-weight: 800; letter-spacing: -0.02em; }
  .sub { color: var(--tg-hint); font-size: 13px; margin-bottom: 24px; }

  .kpis {
    display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; position: relative; z-index: 1;
  }
  .kpi {
    background: rgba(255,255,255,0.06);
    backdrop-filter: blur(20px) saturate(180%);
    -webkit-backdrop-filter: blur(20px) saturate(180%);
    border: 1px solid var(--border-s);
    border-radius: var(--radius);
    padding: 14px 10px;
    text-align: center;
    transition: transform 0.2s, background 0.2s;
  }
  .kpi:active { transform: scale(0.97); background: var(--card-h); }
  .kpi .l {
    font-size: 10.5px; color: var(--tg-hint);
    text-transform: uppercase; letter-spacing: 0.05em; font-weight: 600;
  }
  .kpi .v {
    font-size: 28px; font-weight: 800; margin-top: 4px; line-height: 1;
    background: linear-gradient(135deg, #fff, #b9c5ff);
